/**
 * Sliding Window Rate Limiter for Express.js
 *
 * TRUE sliding window: each request's timestamp is tracked per client IP.
 * On every request we evict timestamps older than `windowMs` relative to
 * NOW, then count what remains. There is no fixed interval that resets the
 * count for everyone at once — the window slides continuously with time.
 *
 * NOTE ON `req.ip` BEHIND PROXIES:
 * `req.ip` reflects the socket's remote address by default. If your app sits
 * behind a reverse proxy / load balancer (Nginx, ELB, Cloudflare, etc.),
 * every request will appear to come from the proxy's IP and all clients will
 * share one bucket. Enable Express's trust proxy setting so `req.ip` is
 * derived from the `X-Forwarded-For` header instead:
 *
 *     app.set('trust proxy', 1);            // trust first hop (typical)
 *     // or app.set('trust proxy', true);   // trust all hops (only if safe)
 *
 * Only trust proxies you control — `X-Forwarded-For` is client-spoofable
 * when the chain is untrusted, which would let attackers evade the limit.
 */

/**
 * @param {Object} [options]
 * @param {number} [options.windowMs=60000]   Window size in milliseconds.
 * @param {number} [options.maxRequests=100]  Max requests allowed per window.
 * @param {number} [options.cleanupMs=60000]  Stale-entry sweep interval (ms).
 * @param {(req) => string} [options.keyGenerator]  Custom client key resolver.
 * @returns {Function & { close: () => void }} Express middleware with close().
 */
function createRateLimiter(options = {}) {
  const windowMs = options.windowMs ?? 60000;
  const maxRequests = options.maxRequests ?? 100;
  const cleanupMs = options.cleanupMs ?? 60000;
  const keyGenerator =
    options.keyGenerator ?? ((req) => req.ip || req.socket?.remoteAddress || 'unknown');

  // Map<clientKey, number[]>  — ascending-sorted arrays of request timestamps.
  const hits = new Map();

  // Periodic sweep: drop entries whose timestamps are all older than windowMs.
  // Per-request pruning already trims active buckets; this reclaims memory for
  // IPs that have gone quiet and would otherwise linger in the Map forever.
  const cleanupTimer = setInterval(() => {
    const cutoff = Date.now() - windowMs;
    for (const [key, timestamps] of hits) {
      // timestamps are ascending, so the last element is the most recent.
      if (timestamps.length === 0 || timestamps[timestamps.length - 1] <= cutoff) {
        hits.delete(key);
      }
    }
  }, cleanupMs);

  // Don't let the cleanup timer keep the Node process alive on its own.
  if (typeof cleanupTimer.unref === 'function') {
    cleanupTimer.unref();
  }

  function middleware(req, res, next) {
    const now = Date.now();
    const windowStart = now - windowMs;
    const key = keyGenerator(req);

    let timestamps = hits.get(key);
    if (!timestamps) {
      timestamps = [];
      hits.set(key, timestamps);
    }

    // Evict everything that fell out of the sliding window. Timestamps are
    // appended in order, so stale entries form a leading prefix — find the
    // first in-window index and splice once.
    let firstValid = 0;
    while (firstValid < timestamps.length && timestamps[firstValid] <= windowStart) {
      firstValid++;
    }
    if (firstValid > 0) {
      timestamps.splice(0, firstValid);
    }

    const count = timestamps.length;

    if (count >= maxRequests) {
      // Over the limit. A slot frees up when the OLDEST in-window timestamp
      // ages out, i.e. at timestamps[0] + windowMs.
      const oldest = timestamps[0];
      const resetMs = oldest + windowMs;
      const retryAfterSec = Math.max(1, Math.ceil((resetMs - now) / 1000));

      res.setHeader('X-RateLimit-Limit', maxRequests);
      res.setHeader('X-RateLimit-Remaining', 0);
      res.setHeader('X-RateLimit-Reset', Math.ceil(resetMs / 1000));
      res.setHeader('Retry-After', retryAfterSec);

      res.status(429).json({
        error: 'Rate limit exceeded',
        retryAfter: retryAfterSec,
      });
      return; // Do NOT call next().
    }

    // Under the limit — record this request and allow it through.
    timestamps.push(now);

    const remaining = maxRequests - timestamps.length;
    // The window is fully clear once the current oldest timestamp expires.
    const resetMs = timestamps[0] + windowMs;

    res.setHeader('X-RateLimit-Limit', maxRequests);
    res.setHeader('X-RateLimit-Remaining', Math.max(0, remaining));
    res.setHeader('X-RateLimit-Reset', Math.ceil(resetMs / 1000));

    next();
  }

  // Stop the cleanup timer (graceful shutdown / tests) and free memory.
  middleware.close = function close() {
    clearInterval(cleanupTimer);
    hits.clear();
  };

  return middleware;
}

